import boto3, json
br = boto3.client('bedrock', region_name='us-east-1')
print('--- INFERENCE PROFILES ---')
try:
    for p in br.list_inference_profiles(maxResults=200).get('inferenceProfileSummaries', []):
        if 'claude' in p['inferenceProfileId'].lower():
            print(p['inferenceProfileId'], '|', p.get('status'))
except Exception as e:
    print('list_inference_profiles FAIL:', str(e)[:300])
print('--- FOUNDATION MODELS (claude only) ---')
try:
    for m in br.list_foundation_models().get('modelSummaries', []):
        if 'claude' in m['modelId'].lower() and 'on_demand' in (m.get('inferenceTypesSupported') or []):
            print(m['modelId'])
except Exception as e:
    print('list_foundation_models FAIL:', str(e)[:300])
